/**
 * Material Design 3 Theme for Docfx
 * Main JavaScript entry point (pre-compiled)
 * Version: 1.1.0
 */

(function() {
  'use strict';

  // ==================== Theme Management ====================
  function initTheme() {
    const theme = localStorage.getItem('theme') || 'auto';
    applyTheme(theme);

    // Listen for system theme changes
    window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', (e) => {
      const currentTheme = localStorage.getItem('theme') || 'auto';
      if (currentTheme === 'auto') {
        document.documentElement.setAttribute('data-applied-theme', e.matches ? 'dark' : 'light');
      }
    });

    // Theme toggle button
    const themeToggle = document.getElementById('theme-toggle');
    if (themeToggle) {
      themeToggle.addEventListener('click', () => {
        const currentTheme = localStorage.getItem('theme') || 'auto';
        const themes = ['light', 'dark', 'auto'];
        const currentIndex = themes.indexOf(currentTheme);
        const nextIndex = (currentIndex + 1) % themes.length;
        const nextTheme = themes[nextIndex];
        localStorage.setItem('theme', nextTheme);
        applyTheme(nextTheme);
      });
    }
  }

  function applyTheme(theme) {
    const root = document.documentElement;
    root.setAttribute('data-theme', theme);

    if (theme === 'auto') {
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      root.setAttribute('data-applied-theme', prefersDark ? 'dark' : 'light');
    } else {
      root.setAttribute('data-applied-theme', theme);
    }
  }

  // ==================== Mobile Navigation ====================
  function initMobileNav() {
    const navToggle = document.getElementById('nav-toggle');
    const navDrawer = document.getElementById('nav-drawer');
    const mdContent = document.querySelector('.md-content');
    const mdFooter = document.querySelector('.md-footer');
    const hasToc = navDrawer && navDrawer.classList.contains('has-toc');

    if (!navToggle || !navDrawer) {
      console.log('Mobile nav elements not found', { navToggle, navDrawer });
      return;
    }

    // Create overlay
    let overlay = document.querySelector('.md-nav-overlay');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.className = 'md-nav-overlay';
      document.body.appendChild(overlay);
    }

    const isMobile = () => window.innerWidth <= 900;

    if (!isMobile()) {
      navToggle.style.display = 'none';
    }

    const toggleNav = (open) => {
      console.log('Toggle nav:', open, 'isMobile:', isMobile());

      if (isMobile()) {
        // Mobile: use 'open' class with overlay
        if (open) {
          navDrawer.classList.add('open');
          overlay.classList.add('visible');
          document.body.style.overflow = 'hidden';
        } else {
          navDrawer.classList.remove('open');
          overlay.classList.remove('visible');
          document.body.style.overflow = '';
        }
      } else {
        // Desktop: only toggle if has TOC
        if (!hasToc) return;

        // Desktop: use 'expanded' class on content (removes margin-left)
        if (open) {
          navDrawer.classList.remove('collapsed');
          if (mdContent) mdContent.classList.remove('expanded');
          if (mdFooter) mdFooter.classList.remove('expanded');
          // Restore custom width if saved
          const savedWidth = localStorage.getItem('navDrawerWidth');
          if (savedWidth) {
            const width = Math.min(Math.max(parseInt(savedWidth), 200), 500);
            navDrawer.style.width = width + 'px';
            if (mdContent) mdContent.style.marginLeft = width + 'px';
            if (mdFooter) mdFooter.style.marginLeft = width + 'px';
          }
        } else {
          navDrawer.classList.add('collapsed');
          if (mdContent) mdContent.classList.add('expanded');
          if (mdFooter) mdFooter.classList.add('expanded');
        }
        // Save state to localStorage
        localStorage.setItem('navCollapsed', !open);
      }
    };

    // Get initial state for desktop
    const getInitialState = () => {
      if (isMobile()) {
        return false; // Mobile: closed by default
      } else {
        // Desktop: check localStorage, default to open
        const saved = localStorage.getItem('navCollapsed');
        return saved !== 'true';
      }
    };

    // Set initial state (only for pages with TOC on desktop)
    const initialState = getInitialState();
    if (!isMobile() && hasToc) {
      if (!initialState) {
        navDrawer.classList.add('collapsed');
        if (mdContent) mdContent.classList.add('expanded');
        if (mdFooter) mdFooter.classList.add('expanded');
      }
    }

    // Handle click on md-icon-button (Web Component) or fallback
    navToggle.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();

      if (isMobile()) {
        const isOpen = navDrawer.classList.contains('open');
        toggleNav(!isOpen);
      } else {
        const isCollapsed = navDrawer.classList.contains('collapsed');
        toggleNav(isCollapsed);
      }
    });

    // Also handle click on the inner span (fallback)
    const innerSpan = navToggle.querySelector('.material-symbols-outlined');
    if (innerSpan) {
      innerSpan.addEventListener('click', (e) => {
        e.preventDefault();
        e.stopPropagation();

        if (isMobile()) {
          const isOpen = navDrawer.classList.contains('open');
          toggleNav(!isOpen);
        } else {
          const isCollapsed = navDrawer.classList.contains('collapsed');
          toggleNav(isCollapsed);
        }
      });
    }

    overlay.addEventListener('click', () => {
      if (isMobile()) {
        toggleNav(false);
      }
    });

    // Close on escape (mobile only)
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && isMobile() && navDrawer.classList.contains('open')) {
        toggleNav(false);
      }
    });

    // Close on link click (mobile only)
    navDrawer.querySelectorAll('a').forEach(link => {
      link.addEventListener('click', () => {
        if (isMobile()) {
          toggleNav(false);
        }
      });
    });

    // Handle resize - switch between mobile and desktop modes
    let resizeTimeout;
    let lastIsMobile = isMobile();
    window.addEventListener('resize', () => {
      clearTimeout(resizeTimeout);
      resizeTimeout = setTimeout(() => {
        const currentIsMobile = isMobile();

        if (currentIsMobile !== lastIsMobile) {
          // Switched between mobile and desktop
          if (currentIsMobile) {
            // Switched to mobile - remove desktop classes
            navDrawer.classList.remove('collapsed');
            if (mdContent) mdContent.classList.remove('expanded');
            if (mdFooter) mdFooter.classList.remove('expanded');
          } else {
            // Switched to desktop - remove mobile classes
            navDrawer.classList.remove('open');
            overlay.classList.remove('visible');
            document.body.style.overflow = '';

            // Restore desktop state from localStorage
            const saved = localStorage.getItem('navCollapsed');
            if (saved === 'true') {
              navDrawer.classList.add('collapsed');
              if (mdContent) mdContent.classList.add('expanded');
              if (mdFooter) mdFooter.classList.add('expanded');
            }
          }
          lastIsMobile = currentIsMobile;
        }
      }, 100);
    });

    console.log('Mobile nav initialized');
  }

  // ==================== TOC (Table of Contents) ====================
  function initToc() {
    const tocContainer = document.getElementById('toc');
    if (!tocContainer) {
      console.log('TOC container not found');
      return;
    }

    const tocRel = getMeta('docfx:tocrel');
    if (!tocRel) {
      console.log('TOC rel meta not found');
      return;
    }

    // Build correct URL for TOC JSON
    const baseUrl = window.location.href.substring(0, window.location.href.lastIndexOf('/') + 1);
    const tocUrl = new URL(tocRel.replace(/\.html$/gi, '.json'), baseUrl);

    console.log('Loading TOC from:', tocUrl.href);

    fetch(tocUrl.href)
      .then(res => {
        if (!res.ok) throw new Error('Failed to load TOC: ' + res.status);
        return res.json();
      })
      .then(data => {
        console.log('TOC data loaded:', data);
        const { items, pdf, pdfFileName } = data;

        if (!items || items.length === 0) {
          console.log('No TOC items');
          return;
        }

        // Build TOC HTML
        const tocHtml = buildTocHtml(items, tocUrl.href);
        const filterHtml = buildTocFilter();
        const pdfHtml = pdf ? buildPdfLink(pdfFileName || 'toc.pdf', tocUrl.href) : '';

        tocContainer.innerHTML = filterHtml + '<div class="flex-fill overflow-y-auto">' + tocHtml + '</div>' + pdfHtml;

        // Initialize expand/collapse
        initTocExpandCollapse(tocContainer);

        // Initialize filter
        initTocFilter(tocContainer);

        // Scroll to active item
        const activeItem = tocContainer.querySelector('li.active');
        if (activeItem) {
          activeItem.scrollIntoView({ block: 'nearest' });
        }

        // Initialize next/prev article
        initNextArticle(items);
      })
      .catch(err => console.error('Failed to load TOC:', err));
  }

  function buildTocHtml(items, tocUrl, level = 0) {
    if (!items || items.length === 0) return '';

    const currentPath = normalizePath(window.location.pathname);
    let html = '<ul>';

    items.forEach(item => {
      const href = item.href ? new URL(item.href, tocUrl).href : null;
      const isActive = href && normalizePath(new URL(href).pathname) === currentPath;
      const hasChildren = item.items && item.items.length > 0;

      let itemClass = '';
      if (isActive) itemClass += ' active';
      if (hasChildren) itemClass += ' expander';

      // Check if any child is active
      const childActive = hasChildren && checkActiveChild(item.items, currentPath, tocUrl);
      if (childActive) itemClass += ' expanded';

      html += `<li class="${itemClass.trim()}">`;

      // Wrapper for the item content (icon + link/text)
      html += '<div class="toc-item-row">';

      if (hasChildren) {
        html += '<span class="expand-stub"></span>';
      }

      if (href) {
        html += `<a class="md-toc-link${isActive ? ' active' : ''}" href="${href}">${escapeHtml(item.name)}</a>`;
      } else {
        html += `<span class="name-only">${escapeHtml(item.name)}</span>`;
      }

      html += '</div>';

      if (hasChildren) {
        html += buildTocHtml(item.items, tocUrl, level + 1);
      }

      html += '</li>';
    });

    html += '</ul>';
    return html;
  }

  function checkActiveChild(items, currentPath, tocUrl) {
    if (!items) return false;
    return items.some(item => {
      if (item.href) {
        try {
          const href = new URL(item.href, tocUrl);
          if (normalizePath(href.pathname) === currentPath) return true;
        } catch (e) {}
      }
      return checkActiveChild(item.items, currentPath, tocUrl);
    });
  }

  function buildTocFilter() {
    const placeholder = getMeta('loc:tocFilter') || 'Filter by title';
    return `<form class="filter">
      <span class="material-symbols-outlined">search</span>
      <input type="search" placeholder="${placeholder}" autocomplete="off">
    </form>`;
  }

  function buildPdfLink(fileName, tocUrl) {
    const label = getMeta('loc:downloadPdf') || 'Download PDF';
    const href = new URL(fileName, tocUrl).href;
    return `<div class="py-2 mb-md-4"><a class="pdf-link" href="${href}">${label}</a></div>`;
  }

  function initTocExpandCollapse(container) {
    container.querySelectorAll('.expand-stub').forEach(stub => {
      stub.addEventListener('click', (e) => {
        e.preventDefault();
        e.stopPropagation();
        const li = stub.closest('li');
        if (li) {
          toggleExpandCollapse(li);
        }
      });
    });

    // Also handle click on the row (toggle expand)
    container.querySelectorAll('.toc-item-row').forEach(row => {
      const li = row.closest('li');
      if (li && li.classList.contains('expander')) {
        // Click on name-only (no link) should toggle expand
        const nameOnly = row.querySelector('.name-only');
        if (nameOnly) {
          nameOnly.style.cursor = 'pointer';
          nameOnly.addEventListener('click', (e) => {
            e.preventDefault();
            toggleExpandCollapse(li);
          });
        }
      }
    });
  }

  function toggleExpandCollapse(li) {
    const isExpanded = li.classList.contains('expanded');

    if (isExpanded) {
      // Collapse with animation
      li.classList.add('collapsing');
      li.classList.remove('expanded');

      // Remove collapsing class after animation
      const ul = li.querySelector(':scope > ul');
      if (ul) {
        ul.addEventListener('animationend', function handler() {
          li.classList.remove('collapsing');
          ul.removeEventListener('animationend', handler);
        });
      }
    } else {
      // Expand with animation
      li.classList.remove('collapsing');
      li.classList.add('expanded');
    }
  }

  function initTocFilter(container) {
    const input = container.querySelector('.filter input');
    if (!input) return;

    input.addEventListener('input', (e) => {
      const filter = e.target.value.toLowerCase().trim();
      localStorage.setItem('tocFilter', filter);
      localStorage.setItem('tocFilterUrl', window.location.href);
      filterToc(container, filter);
    });

    // Restore filter
    const savedFilter = localStorage.getItem('tocFilter') || '';
    if (savedFilter) {
      input.value = savedFilter;
      filterToc(container, savedFilter);
    }
  }

  function filterToc(container, filter) {
    const items = container.querySelectorAll('li');
    items.forEach(item => {
      const link = item.querySelector('a');
      if (link) {
        const text = link.textContent.toLowerCase();
        const hasMatchingChildren = item.querySelector('ul') &&
          Array.from(item.querySelectorAll('ul li a')).some(a =>
            a.textContent.toLowerCase().includes(filter)
          );

        if (filter === '' || text.includes(filter) || hasMatchingChildren) {
          item.style.display = '';
          if (filter !== '' && hasMatchingChildren) {
            item.classList.add('expanded');
          }
        } else {
          item.style.display = 'none';
        }
      }
    });
  }

  function initNextArticle(items) {
    const nextArticle = document.getElementById('nextArticle');
    if (!nextArticle) return;

    const flatItems = flattenToc(items);
    const currentPath = normalizePath(window.location.pathname);

    let currentIndex = -1;
    flatItems.forEach((item, i) => {
      if (item.href) {
        try {
          const href = new URL(item.href, window.location.origin);
          if (normalizePath(href.pathname) === currentPath) {
            currentIndex = i;
          }
        } catch (e) {}
      }
    });

    if (currentIndex === -1) return;

    const prev = flatItems[currentIndex - 1];
    const next = flatItems[currentIndex + 1];

    if (!prev && !next) return;

    const prevLabel = getMeta('loc:prevArticle') || 'Previous';
    const nextLabel = getMeta('loc:nextArticle') || 'Next';

    let html = '';
    if (prev) {
      html += `<div class="prev"><span><span class="material-symbols-outlined">chevron_left</span> ${prevLabel}</span> <a href="${prev.href}">${escapeHtml(prev.name)}</a></div>`;
    }
    if (next) {
      html += `<div class="next"><span>${nextLabel} <span class="material-symbols-outlined">chevron_right</span></span> <a href="${next.href}">${escapeHtml(next.name)}</a></div>`;
    }

    nextArticle.innerHTML = html;
  }

  function flattenToc(items, result = []) {
    items.forEach(item => {
      if (item.href) {
        result.push(item);
      }
      if (item.items) {
        flattenToc(item.items, result);
      }
    });
    return result;
  }

  // ==================== Navbar ====================
  function initNavbar() {
    const navbar = document.getElementById('navbar');
    if (!navbar) {
      console.log('Navbar container not found');
      return;
    }

    const navRel = getMeta('docfx:navrel');
    if (!navRel) {
      console.log('Nav rel meta not found');
      return;
    }

    // Build correct URL for nav JSON
    const baseUrl = window.location.href.substring(0, window.location.href.lastIndexOf('/') + 1);
    const navUrl = new URL(navRel.replace(/\.html$/gi, '.json'), baseUrl);

    console.log('Loading navbar from:', navUrl.href);

    fetch(navUrl.href)
      .then(res => {
        if (!res.ok) throw new Error('Failed to load navbar: ' + res.status);
        return res.json();
      })
      .then(data => {
        console.log('Navbar data loaded:', data);
        const { items } = data;
        if (!items || items.length === 0) {
          console.log('No navbar items');
          return;
        }

        let html = '';
        items.forEach(item => {
          if (item.items && item.items.length > 0) {
            // Dropdown menu
            html += `<div class="md-nav-dropdown">
              <a class="md-nav-link" href="#">
                ${escapeHtml(item.name)}
                <span class="material-symbols-outlined">expand_more</span>
              </a>
              <div class="md-dropdown-menu">`;
            item.items.forEach(subItem => {
              const href = new URL(subItem.href, navUrl.href).href;
              html += `<a class="md-nav-link" href="${href}">${escapeHtml(subItem.name)}</a>`;
            });
            html += '</div></div>';
          } else if (item.href) {
            const href = new URL(item.href, navUrl.href).href;
            html += `<a class="md-nav-link" href="${href}">${escapeHtml(item.name)}</a>`;
          }
        });

        navbar.innerHTML = html;

        const isMobile = () => window.innerWidth <= 900;

        // Initialize dropdown
        initDropdowns(navbar);
        if(isMobile()) {
          // Create mobile navbar in drawer
          createMobileNavbar(items, navUrl.href);
        }
      })
      .catch(err => console.error('Failed to load navbar:', err));
  }

  function createMobileNavbar(items, navBaseUrl) {
    const navDrawer = document.getElementById('nav-drawer');
    if (!navDrawer) {
      console.log('createMobileNavbar: nav-drawer not found');
      return;
    }

    console.log('createMobileNavbar: Creating mobile navbar with', items.length, 'items');

    // Check if mobile navbar already exists
    let mobileNavbar = navDrawer.querySelector('.md-navbar-nav-mobile');
    if (!mobileNavbar) {
      mobileNavbar = document.createElement('nav');
      mobileNavbar.className = 'md-navbar-nav-mobile';
      mobileNavbar.id = 'navbar-mobile';
      // Insert at the top of the drawer
      navDrawer.insertBefore(mobileNavbar, navDrawer.firstChild);
      console.log('createMobileNavbar: Created navbar-mobile element');
    }

    let html = '';
    items.forEach(item => {
      if (item.items && item.items.length > 0) {
        // Dropdown menu for mobile
        html += `<div class="md-nav-dropdown">
          <a class="md-nav-link" href="#">
            ${escapeHtml(item.name)}
            <span class="material-symbols-outlined">expand_more</span>
          </a>
          <div class="md-dropdown-menu">`;
        item.items.forEach(subItem => {
          const href = new URL(subItem.href, navBaseUrl).href;
          html += `<a class="md-nav-link" href="${href}">${escapeHtml(subItem.name)}</a>`;
        });
        html += '</div></div>';
      } else if (item.href) {
        const href = new URL(item.href, navBaseUrl).href;
        html += `<a class="md-nav-link" href="${href}">${escapeHtml(item.name)}</a>`;
      }
    });

    mobileNavbar.innerHTML = html;
    console.log('createMobileNavbar: HTML generated, length:', html.length);

    // Initialize dropdowns for mobile navbar
    initDropdowns(mobileNavbar);

    // Close drawer when clicking a link
    mobileNavbar.querySelectorAll('.md-nav-link').forEach(link => {
      link.addEventListener('click', (e) => {
        if (!link.closest('.md-nav-dropdown') || link.closest('.md-dropdown-menu')) {
          // Close the drawer on mobile
          if (window.innerWidth <= 900) {
            const overlay = document.querySelector('.md-nav-overlay');
            if (overlay) overlay.classList.remove('visible');
            navDrawer.classList.remove('open');
            document.body.style.overflow = '';
          }
        }
      });
    });
  }

  function initDropdowns(navbar) {
    navbar.querySelectorAll('.md-nav-dropdown').forEach(dropdown => {
      const trigger = dropdown.querySelector('.md-nav-link');
      const menu = dropdown.querySelector('.md-dropdown-menu');

      trigger.addEventListener('click', (e) => {
        e.preventDefault();
        const isOpen = dropdown.classList.contains('open');

        // Close all other dropdowns
        navbar.querySelectorAll('.md-nav-dropdown.open').forEach(d => {
          if (d !== dropdown) d.classList.remove('open');
        });

        dropdown.classList.toggle('open');
      });
    });

    // Close dropdowns when clicking outside
    document.addEventListener('click', (e) => {
      if (!navbar.contains(e.target)) {
        navbar.querySelectorAll('.md-nav-dropdown.open').forEach(d => {
          d.classList.remove('open');
        });
      }
    });
  }

  // ==================== Breadcrumb ====================
  function initBreadcrumb() {
    const breadcrumb = document.getElementById('breadcrumb');
    if (!breadcrumb) return;

    const tocRel = getMeta('docfx:tocrel');
    const navRel = getMeta('docfx:navrel');

    const baseUrl = window.location.href.substring(0, window.location.href.lastIndexOf('/') + 1);

    Promise.all([
      navRel ? fetch(new URL(navRel.replace(/\.html$/gi, '.json'), baseUrl).href).then(r => r.json()).catch(() => ({ items: [] })) : Promise.resolve({ items: [] }),
      tocRel ? fetch(new URL(tocRel.replace(/\.html$/gi, '.json'), baseUrl).href).then(r => r.json()).catch(() => ({ items: [] })) : Promise.resolve({ items: [] })
    ]).then(([navData, tocData]) => {
      const currentPath = normalizePath(window.location.pathname);
      const breadcrumbItems = [];

      // Find path in nav items
      findPath(navData.items || [], currentPath, breadcrumbItems, baseUrl);
      // Find path in toc items
      findPath(tocData.items || [], currentPath, breadcrumbItems, baseUrl);

      if (breadcrumbItems.length === 0) return;

      let html = '<ol class="md-breadcrumb">';
      breadcrumbItems.forEach(item => {
        html += `<li class="md-breadcrumb-item"><a href="${item.href}">${escapeHtml(item.name)}</a></li>`;
      });
      html += '</ol>';

      breadcrumb.innerHTML = html;
    }).catch(err => console.error('Failed to load breadcrumb:', err));
  }

  function findPath(items, currentPath, result, baseUrl, parentHref = null) {
    if (!items) return false;

    for (const item of items) {
      if (item.href) {
        try {
          const href = new URL(item.href, baseUrl).href;
          if (normalizePath(new URL(href).pathname) === currentPath) {
            result.push({ name: item.name, href });
            return true;
          }
        } catch (e) {}
      }
      if (item.items && findPath(item.items, currentPath, result, baseUrl, item.href)) {
        if (item.href) {
          try {
            result.unshift({ name: item.name, href: new URL(item.href, baseUrl).href });
          } catch (e) {}
        }
        return true;
      }
    }
    return false;
  }

  // ==================== Affix (In This Article) ====================
  function initAffix() {
    const affix = document.getElementById('affix');
    if (!affix) return;

    const headings = document.querySelectorAll('article h2, article h3');
    if (headings.length === 0) {
      affix.style.display = 'none';
      return;
    }

    const label = getMeta('loc:inThisArticle') || 'In this article';
    let html = `<h5 class="md-typescale-label-large">${label}</h5><ul class="md-affix-list">`;

    headings.forEach(h => {
      if (h.id) {
        const level = h.tagName === 'H2' ? 'h2' : 'h3';
        const indent = h.tagName === 'H3' ? 'style="margin-left: 12px;"' : '';
        html += `<li ${indent}><a class="md-affix-link md-affix-${level}" href="#${h.id}">${escapeHtml(h.textContent)}</a></li>`;
      }
    });

    html += '</ul>';
    affix.innerHTML = html;

    // Track active heading
    trackActiveHeading(headings);
  }

  function trackActiveHeading(headings) {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const id = entry.target.id;
          document.querySelectorAll('#affix a').forEach(a => {
            a.classList.remove('active');
            if (a.getAttribute('href') === `#${id}`) {
              a.classList.add('active');
            }
          });
        }
      });
    }, { rootMargin: '-100px 0px -80% 0px' });

    headings.forEach(h => {
      if (h.id) observer.observe(h);
    });
  }

  // ==================== Anchors ====================
  function initAnchors() {
    const headings = document.querySelectorAll('article h2, article h3, article h4');
    headings.forEach(heading => {
      if (heading.id && !heading.querySelector('.anchor')) {
        const anchor = document.createElement('a');
        anchor.className = 'anchor';
        anchor.href = '#' + heading.id;
        anchor.innerHTML = '#';
        anchor.style.cssText = 'margin-left: 8px; color: var(--md-sys-color-outline); opacity: 0; transition: opacity 0.2s; text-decoration: none;';
        heading.appendChild(anchor);
        heading.addEventListener('mouseenter', () => anchor.style.opacity = '1');
        heading.addEventListener('mouseleave', () => anchor.style.opacity = '0');
      }
    });
  }

  // ==================== Search ====================
  let searchWorker = null;
  let currentQuery = '';

  function initSearch() {
    const searchQuery = document.getElementById('search-query');
    const searchForm = document.getElementById('search');
    if (!searchQuery) return;

    const relHref = getMeta('docfx:rel') || '';

    // Try to enable search when index is ready
    if (window.Worker) {
      try {
        const workerUrl = relHref + 'public/search-worker.min.js';
        searchWorker = new Worker(workerUrl);

        searchWorker.onmessage = function(e) {
          const data = e.data;
          if (data.e === 'index-ready') {
            searchQuery.disabled = false;
            searchQuery.placeholder = getMeta('loc:searchQuery') || 'Search';
            console.log('Search index ready');
          } else if (data.e === 'query-ready') {
            renderSearchResults(data.d, 0);
          } else if (data.e === 'index-error') {
            console.error('Search index error:', data.error);
            searchQuery.disabled = false;
            searchQuery.placeholder = 'Search unavailable';
          }
        };

        searchWorker.onerror = function(e) {
          console.error('Search worker error:', e);
          searchQuery.disabled = false;
          searchQuery.placeholder = 'Search unavailable';
        };

        // Initialize the worker
        searchWorker.postMessage({ init: { lunrLanguages: [] } });

        // Handle input
        searchQuery.addEventListener('input', debounce(onSearchInput, 300));

        // Prevent form submission
        if (searchForm) {
          searchForm.addEventListener('submit', (e) => e.preventDefault());
        }
      } catch (e) {
        console.error('Search worker not available:', e);
        searchQuery.disabled = false;
      }
    } else {
      searchQuery.disabled = false;
      searchQuery.placeholder = 'Search not supported';
    }
  }

  function onSearchInput(e) {
    const query = e.target.value.trim();
    currentQuery = query;

    if (query === '') {
      hideSearchResults();
    } else if (searchWorker) {
      searchWorker.postMessage({ q: query });
    }
  }

  function renderSearchResults(hits, page) {
    const resultsContainer = document.getElementById('search-results');
    if (!resultsContainer) return;

    if (hits.length === 0) {
      const noResultsText = getMeta('loc:searchNoResults') || 'No results for "{query}"';
      resultsContainer.innerHTML = `<div class="search-no-results">${noResultsText.replace('{query}', escapeHtml(currentQuery))}</div>`;
      resultsContainer.classList.add('visible');
      return;
    }

    const resultsCountText = getMeta('loc:searchResultsCount') || '{count} results for "{query}"';
    const numPerPage = 10;
    const totalPages = Math.ceil(hits.length / numPerPage);
    const start = page * numPerPage;
    const curHits = hits.slice(start, start + numPerPage);
    const relHref = getMeta('docfx:rel') || '';

    let html = `<div class="search-header">${resultsCountText.replace('{count}', hits.length).replace('{query}', escapeHtml(currentQuery))}</div>`;
    html += '<div class="search-items">';

    curHits.forEach(hit => {
      const itemHref = relHref + hit.href + '?q=' + encodeURIComponent(currentQuery);
      const itemBrief = hit.summary ? extractContentBrief(hit.summary, currentQuery) : '';

      html += `
        <a href="${itemHref}" class="search-item">
          <div class="search-item-title">${markText(hit.title, currentQuery)}</div>
          <div class="search-item-href">${markText(hit.href, currentQuery)}</div>
          ${itemBrief ? `<div class="search-item-brief">${markText(itemBrief, currentQuery)}</div>` : ''}
        </a>`;
    });

    html += '</div>';

    // Pagination
    if (totalPages > 1) {
      html += '<div class="search-pagination">';
      html += `<button class="search-page-btn" data-page="${page - 1}" ${page <= 0 ? 'disabled' : ''}>
        <span class="material-symbols-outlined">chevron_left</span>
      </button>`;

      const maxVisiblePages = 5;
      const startPage = Math.max(0, Math.min(page - 2, totalPages - maxVisiblePages));
      const endPage = Math.min(totalPages, startPage + maxVisiblePages);

      for (let i = startPage; i < endPage; i++) {
        html += `<button class="search-page-btn ${i === page ? 'active' : ''}" data-page="${i}">${i + 1}</button>`;
      }

      html += `<button class="search-page-btn" data-page="${page + 1}" ${page >= totalPages - 1 ? 'disabled' : ''}>
        <span class="material-symbols-outlined">chevron_right</span>
      </button>`;
      html += '</div>';
    }

    resultsContainer.innerHTML = html;
    resultsContainer.classList.add('visible');

    // Handle pagination clicks
    resultsContainer.querySelectorAll('.search-page-btn').forEach(btn => {
      btn.addEventListener('click', (e) => {
        e.preventDefault();
        const targetPage = parseInt(btn.dataset.page);
        if (targetPage >= 0 && targetPage < totalPages) {
          renderSearchResults(hits, targetPage);
        }
      });
    });

    // Close on item click
    resultsContainer.querySelectorAll('.search-item').forEach(item => {
      item.addEventListener('click', () => {
        hideSearchResults();
      });
    });
  }

  function extractContentBrief(content, query) {
    const briefOffset = 512;
    const words = query.split(/\s+/g).filter(w => w.length > 0);
    if (words.length === 0) return content.slice(0, briefOffset) + '...';

    const queryIndex = content.toLowerCase().indexOf(words[0].toLowerCase());
    if (queryIndex > briefOffset) {
      return '...' + content.slice(queryIndex - briefOffset, queryIndex + briefOffset) + '...';
    } else if (queryIndex >= 0) {
      return content.slice(0, queryIndex + briefOffset) + '...';
    }
    return content.slice(0, briefOffset) + '...';
  }

  function markText(text, query) {
    if (!query) return escapeHtml(text);

    const words = query.split(/\s+/g).filter(w => w.length > 0);
    const wordsLower = words.map(w => w.toLowerCase());
    const textLower = text.toLowerCase();
    let result = '';
    let lastEnd = 0;

    for (let i = 0; i < wordsLower.length; i++) {
      const word = wordsLower[i];
      const index = textLower.indexOf(word, lastEnd);
      if (index >= 0) {
        result += escapeHtml(text.slice(lastEnd, index));
        result += '<mark>' + escapeHtml(text.slice(index, index + word.length)) + '</mark>';
        lastEnd = index + word.length;
      }
    }
    result += escapeHtml(text.slice(lastEnd));
    return result;
  }

  function hideSearchResults() {
    const resultsContainer = document.getElementById('search-results');
    if (resultsContainer) {
      resultsContainer.classList.remove('visible');
      resultsContainer.innerHTML = '';
    }
  }

  function debounce(func, wait) {
    let timeout;
    return function executedFunction(...args) {
      const later = () => {
        clearTimeout(timeout);
        func(...args);
      };
      clearTimeout(timeout);
      timeout = setTimeout(later, wait);
    };
  }

  // ==================== Code Copy ====================
  function initCodeCopy() {
    document.querySelectorAll('.codewrapper').forEach(wrapper => {
      const pre = wrapper.querySelector('pre');
      const code = wrapper.querySelector('code');
      if (!pre || !code) return;

      // Create copy button
      const copyBtn = document.createElement('button');
      copyBtn.className = 'code-action-btn';
      copyBtn.innerHTML = '<span class="material-symbols-outlined">content_copy</span>';
      copyBtn.title = 'Copy code';
      // copyBtn.setAttribute('data-tooltip', 'Copy');

      // Create action container
      const actionContainer = document.createElement('div');
      actionContainer.className = 'code-action';
      actionContainer.appendChild(copyBtn);
      wrapper.appendChild(actionContainer);

      // Handle click
      copyBtn.addEventListener('click', async () => {
        try {
          await navigator.clipboard.writeText(code.textContent);
          copyBtn.innerHTML = '<span class="material-symbols-outlined">check</span>';
          copyBtn.setAttribute('data-tooltip', 'Copied!');
          setTimeout(() => {
            copyBtn.innerHTML = '<span class="material-symbols-outlined">content_copy</span>';
            copyBtn.removeAttribute('data-tooltip');
          }, 2000);
        } catch (err) {
          console.error('Failed to copy:', err);
        }
      });
    });

    // Also add copy button to standalone pre > code blocks
    document.querySelectorAll('article pre > code').forEach(code => {
      const wrapper = code.parentElement;
      if (wrapper.classList.contains('codewrapper')) return;

      // Create copy button
      const copyBtn = document.createElement('button');
      copyBtn.className = 'code-action-btn';
      copyBtn.innerHTML = '<span class="material-symbols-outlined">content_copy</span>';
      copyBtn.title = 'Copy code';
      // copyBtn.setAttribute('data-tooltip', 'Copy');

      // Create action container
      const actionContainer = document.createElement('div');
      actionContainer.className = 'code-action';
      actionContainer.appendChild(copyBtn);
      wrapper.style.position = 'relative';
      wrapper.appendChild(actionContainer);

      // Handle click
      copyBtn.addEventListener('click', async () => {
        try {
          await navigator.clipboard.writeText(code.textContent);
          copyBtn.innerHTML = '<span class="material-symbols-outlined">check</span>';
          copyBtn.setAttribute('data-tooltip', 'Copied!');
          setTimeout(() => {
            copyBtn.innerHTML = '<span class="material-symbols-outlined">content_copy</span>';
            copyBtn.removeAttribute('data-tooltip');
          }, 2000);
        } catch (err) {
          console.error('Failed to copy:', err);
        }
      });
    });
  }

  // ==================== Utilities ====================
  function getMeta(name) {
    const meta = document.querySelector(`meta[name="${name}"]`);
    return meta ? meta.content : null;
  }

  function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }

  function normalizePath(path) {
    return path
      .replace(/\/index\.html$/gi, '/')
      .replace(/\.html$/gi, '')
      .replace(/\/$/gi, '')
      .toLowerCase();
  }

  // ==================== Navigation Drawer Resize ====================
  function initNavResize() {
    const navDrawer = document.getElementById('nav-drawer');
    const mdContent = document.querySelector('.md-content');
    const mdFooter = document.querySelector('.md-footer');

    if (!navDrawer) return;

    // Check if we're on desktop
    const isDesktop = () => window.innerWidth > 900;

    // Load saved width
    const savedWidth = localStorage.getItem('navDrawerWidth');
    if (savedWidth && isDesktop()) {
      const width = Math.min(Math.max(parseInt(savedWidth), 200), 500);
      navDrawer.style.width = width + 'px';
      if (mdContent) mdContent.style.marginLeft = width + 'px';
      if (mdFooter) mdFooter.style.marginLeft = width + 'px';
    }

    // Create resize handle
    let resizeHandle = navDrawer.querySelector('.md-nav-resize-handle');
    if (!resizeHandle) {
      resizeHandle = document.createElement('div');
      resizeHandle.className = 'md-nav-resize-handle';
      navDrawer.appendChild(resizeHandle);
    }

    let isResizing = false;
    let startX = 0;
    let startWidth = 0;

    resizeHandle.addEventListener('mousedown', (e) => {
      if (!isDesktop()) return;
      e.preventDefault();
      isResizing = true;
      startX = e.clientX;
      startWidth = navDrawer.offsetWidth;
      resizeHandle.classList.add('dragging');
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
    });

    document.addEventListener('mousemove', (e) => {
      if (!isResizing) return;

      const deltaX = e.clientX - startX;
      const newWidth = Math.min(Math.max(startWidth + deltaX, 200), 500);

      navDrawer.style.width = newWidth + 'px';
      if (mdContent) mdContent.style.marginLeft = newWidth + 'px';
      if (mdFooter) mdFooter.style.marginLeft = newWidth + 'px';
    });

    document.addEventListener('mouseup', () => {
      if (isResizing) {
        isResizing = false;
        resizeHandle.classList.remove('dragging');
        document.body.style.cursor = '';
        document.body.style.userSelect = '';

        // Save width to localStorage
        if (isDesktop()) {
          localStorage.setItem('navDrawerWidth', navDrawer.offsetWidth);
        }
      }
    });

    // Handle window resize - reset to default on mobile
    window.addEventListener('resize', () => {
      if (!isDesktop()) {
        navDrawer.style.width = '';
        if (mdContent) mdContent.style.marginLeft = '';
        if (mdFooter) mdFooter.style.marginLeft = '';
      } else {
        // Restore saved width on desktop
        const savedWidth = localStorage.getItem('navDrawerWidth');
        if (savedWidth && !navDrawer.classList.contains('collapsed')) {
          const width = Math.min(Math.max(parseInt(savedWidth), 200), 500);
          navDrawer.style.width = width + 'px';
          if (mdContent) mdContent.style.marginLeft = width + 'px';
          if (mdFooter) mdFooter.style.marginLeft = width + 'px';
        }
      }
    });
  }

  // ==================== Initialize ====================
  document.addEventListener('DOMContentLoaded', () => {
    console.log('Initializing Material Design 3 theme...');

    initTheme();
    initMobileNav();
    initNavResize();
    initToc();
    initNavbar();
    initBreadcrumb();
    initAffix();
    initAnchors();
    initSearch();

    // Mark as ready
    window.docfx = window.docfx || {};
    window.docfx.ready = true;

    console.log('Material Design 3 theme initialized.');
  });

  // Initialize code copy after page load
  window.addEventListener('load', () => {
    initCodeCopy();
  });

  // Expose global functions
  window.initTheme = initTheme;
  window.initMobileNav = initMobileNav;
})();
